import React, { useState, useEffect } from 'react';  // ReactとuseState、useEffectをインポート

const Event = () => {  // Eventコンポーネントの定義
  const [events, setEvents] = useState([]);  // eventsとsetEventsをuseStateフックで定義
  const [newEvent, setNewEvent] = useState({ event_name: '', event_state: 'draft' });  // newEventとsetNewEventをuseStateフックで定義

  // イベントリストを取得する
  const fetchEvents = async () => {  // fetchEvents関数の定義
    const response = await fetch('http://localhost:8000/event/get');  // イベントリストを取得するためのfetchリクエスト
    const data = await response.json();  // レスポンスデータをJSON形式で取得
    setEvents(data);  // 取得したデータをeventsにセット
  };

  // コンポーネントのマウント時にイベントリストを取得
  useEffect(() => {  // useEffectフックの使用
    fetchEvents();  // マウント時にfetchEventsを実行
  }, []);  // 空の依存配列を渡すことで初回レンダリング時のみ実行されるように設定

  // 新しいイベントを登録する
  const registerEvent = async (e) => {  // registerEvent関数の定義
    e.preventDefault();  // デフォルトのイベントをキャンセル
    await fetch('http://localhost:8000/event/register', {  // 新しいイベントを登録するためのfetchリクエスト
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newEvent)  // newEventをJSON形式に変換してリクエストボディに設定
    });
    setNewEvent({ event_name: '', event_state: 'draft' });  // newEventをリセット
    fetchEvents(); // リストを更新
  };

  // イベントを更新する
  const updateEvent = async (eventToUpdate) => {  // updateEvent関数の定義
    await fetch(`http://localhost:8000/event/edit/${eventToUpdate.event_id}`, {  // イベントを更新するためのfetchリクエスト
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(eventToUpdate)  // eventToUpdateをJSON形式に変換してリクエストボディに設定
    });
    fetchEvents(); // リストを更新
  };

  // イベントを削除する
  const deleteEvent = async (eventId) => {  // deleteEvent関数の定義
    await fetch(`http://localhost:8000/event/delete/${eventId}`, { method: 'DELETE' });  // イベントを削除するためのfetchリクエスト
    fetchEvents(); // リストを更新
  };

  return (  // コンポーネントのレンダリング
    <div>  // ルート要素
      <h2>イベント管理</h2>  // タイトル
      {/* イベント登録フォーム */}
      <form onSubmit={registerEvent}>  // 登録フォーム
        {/* フォームの中身 */}
      </form>
      {/* イベントリスト */}
      {events.map((event) => (  // イベントリストのマッピング
        <div key={event.event_id}>  // キー付きのdiv要素
          {/* イベント情報の入力フォームとボタン */}
        </div>
      ))}
    </div>
  );
};

export default Event;  // Eventコンポーネントをエクスポート
